import{_ as n,c as a,o as e,a2 as l}from"./chunks/framework.aRVg8jgk.js";const m=JSON.parse('{"title":"Performance Tuning Guide","description":"Tuning guide for Lynq at scale. Covers concurrency flags, requeue intervals, watch predicates, and large node count recommendations.","frontmatter":{"description":"Tuning guide for Lynq at scale. Covers concurrency flags, requeue intervals, watch predicates, and large node count recommendations."},"headers":[],"relativePath":"performance.md","filePath":"performance.md","lastUpdated":1779353865000}'),o={name:"performance.md"};function p(r,s,t,i,c,d){return e(),a("div",null,[...s[0]||(s[0]=[l(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /performance.md for this page in Markdown format</div><h1 id="performance-tuning-guide" tabindex="-1">Performance Tuning Guide <a class="header-anchor" href="#performance-tuning-guide" aria-label="Permalink to &quot;Performance Tuning Guide&quot;">​</a></h1><p>Practical optimization strategies for scaling Lynq to hundreds of nodes.</p><h2 id="understanding-performance" tabindex="-1">Understanding Performance <a class="header-anchor" href="#understanding-performance" aria-label="Permalink to &quot;Understanding Performance&quot;">​</a></h2><p>Lynq uses four reconciliation layers:</p><ol><li><strong>Event-Driven (Immediate)</strong>: Reacts to spec or non-<code>lynq.sh/*</code> annotation changes on watched child resources via <code>Owns()</code> watches, and to LynqNode CR changes.</li><li><strong>Periodic (30 seconds)</strong>: Refreshes child-resource status into LynqNode status (so <code>readyResources</code> / <code>failedResources</code> reflect cluster reality quickly).</li><li><strong>Force-Reapply (<code>ForceReapplyInterval</code>, default 10 minutes)</strong>: Per-LynqNode periodic resync that bypasses the per-resource skip check and re-applies every child resource unconditionally. This is Lynq&#39;s drift-correction backstop.</li><li><strong>Database Sync (Configurable)</strong>: Syncs node data at defined intervals (default: 30 seconds).</li></ol><p>Drift correction operates on two channels:</p><ul><li><strong>Immediate (watch-driven)</strong> — external mutations that bump <code>metadata.generation</code> or alter the <code>lynq.sh/applied-hash</code> annotation are caught on the next reconcile cycle (sub-30s typical).</li><li><strong>~10 minute (periodic force-reapply)</strong> — external mutations that preserved <code>applied-hash</code> are caught on the next <code>ForceReapplyInterval</code>-gated cycle. This trades a longer correction window for a structurally race-free apply path (no post-apply MergePatch).</li></ul><h2 id="configuration-tuning" tabindex="-1">Configuration Tuning <a class="header-anchor" href="#configuration-tuning" aria-label="Permalink to &quot;Configuration Tuning&quot;">​</a></h2><h3 id="_1-database-sync-interval" tabindex="-1">1. Database Sync Interval <a class="header-anchor" href="#_1-database-sync-interval" aria-label="Permalink to &quot;1. Database Sync Interval&quot;">​</a></h3><p>Adjust how frequently the operator checks your database:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">apiVersion</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">operator.lynq.sh/v1</span></span>
<span class="line"><span style="color:#85E89D;">kind</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">LynqHub</span></span>
<span class="line"><span style="color:#85E89D;">metadata</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">my-hub</span></span>
<span class="line"><span style="color:#85E89D;">spec</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  source</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    syncInterval</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">1m</span><span style="color:#6A737D;">  # Default: 30 seconds</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>Recommendations:</strong></p><ul><li><strong>High-frequency changes</strong>: <code>30s</code> - Faster node provisioning, higher DB load</li><li><strong>Normal usage</strong>: <code>1m</code> (default) - Balanced performance</li><li><strong>Stable nodes</strong>: <code>5m</code> - Lower DB load, slower updates</li></ul><h3 id="_2-resource-wait-timeouts" tabindex="-1">2. Resource Wait Timeouts <a class="header-anchor" href="#_2-resource-wait-timeouts" aria-label="Permalink to &quot;2. Resource Wait Timeouts&quot;">​</a></h3><p>Control how long to wait for resources to become ready:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">deployments</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">app</span></span>
<span class="line"><span style="color:#85E89D;">    waitForReady</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">true</span></span>
<span class="line"><span style="color:#85E89D;">    timeoutSeconds</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">300</span><span style="color:#6A737D;">  # Default: 5 minutes (max: 3600)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Recommendations:</strong></p><ul><li><strong>Fast services</strong>: <code>60s</code> - Quick deployments (&lt; 1 min)</li><li><strong>Normal apps</strong>: <code>300s</code> (default) - Standard deployments</li><li><strong>Heavy apps</strong>: <code>600s</code> - Database migrations, complex initialization</li><li><strong>Skip waiting</strong>: Set <code>waitForReady: false</code> for non-critical resources</li></ul><h3 id="_3-creation-policy-optimization" tabindex="-1">3. Creation Policy Optimization <a class="header-anchor" href="#_3-creation-policy-optimization" aria-label="Permalink to &quot;3. Creation Policy Optimization&quot;">​</a></h3><p>Reduce unnecessary reconciliations:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">configMaps</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">init-config</span></span>
<span class="line"><span style="color:#85E89D;">    creationPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Once</span><span style="color:#6A737D;">  # Create once, never reapply</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Use Cases:</strong></p><ul><li><code>Once</code>: Init scripts, immutable configs, security resources</li><li><code>WhenNeeded</code> (default): Normal resources that may need updates</li></ul><h2 id="template-optimization" tabindex="-1">Template Optimization <a class="header-anchor" href="#template-optimization" aria-label="Permalink to &quot;Template Optimization&quot;">​</a></h2><h3 id="_1-keep-templates-simple" tabindex="-1">1. Keep Templates Simple <a class="header-anchor" href="#_1-keep-templates-simple" aria-label="Permalink to &quot;1. Keep Templates Simple&quot;">​</a></h3><p><strong>✅ Good - Efficient template:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">nameTemplate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;{{ .uid }}-app&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>❌ Bad - Complex template:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">nameTemplate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;{{ .uid }}-{{ .region }}-{{ .planId }}-{{ now | date </span><span style="color:#79B8FF;">\\&quot;</span><span style="color:#9ECBFF;">20060102</span><span style="color:#79B8FF;">\\&quot;</span><span style="color:#9ECBFF;"> }}&quot;</span></span>
<span class="line"><span style="color:#6A737D;"># Avoid: timestamps, random values, complex logic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Tips:</strong></p><ul><li>Keep templates simple and predictable</li><li>Avoid <code>now</code>, <code>randAlphaNum</code>, or other non-deterministic functions</li><li>Use consistent naming patterns</li><li>Cache-friendly templates improve performance</li></ul><h3 id="_2-dependency-graph-optimization" tabindex="-1">2. Dependency Graph Optimization <a class="header-anchor" href="#_2-dependency-graph-optimization" aria-label="Permalink to &quot;2. Dependency Graph Optimization&quot;">​</a></h3><p><strong>✅ Good - Shallow dependency tree:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">namespace</span><span style="color:#6A737D;">      # No dependencies</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">deployment</span><span style="color:#6A737D;">     # Depends on: namespace</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">service</span><span style="color:#6A737D;">        # Depends on: deployment</span></span>
<span class="line"><span style="color:#6A737D;"># Depth: 3 - Resources can be created in parallel groups</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>❌ Bad - Deep dependency tree:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">a</span><span style="color:#6A737D;">              # No dependencies</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">b</span><span style="color:#6A737D;">              # Depends on: a</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">c</span><span style="color:#6A737D;">              # Depends on: b</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">d</span><span style="color:#6A737D;">              # Depends on: c</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">e</span><span style="color:#6A737D;">              # Depends on: d</span></span>
<span class="line"><span style="color:#6A737D;"># Depth: 5 - Fully sequential, slow</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>Impact:</strong></p><ul><li>Shallow trees enable parallel execution</li><li>Deep trees force sequential execution</li><li>Each level adds wait time</li></ul><h3 id="_3-minimize-resource-count" tabindex="-1">3. Minimize Resource Count <a class="header-anchor" href="#_3-minimize-resource-count" aria-label="Permalink to &quot;3. Minimize Resource Count&quot;">​</a></h3><p><strong>Example:</strong> Create 5 essential resources per node instead of 15</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Essential only</span></span>
<span class="line"><span style="color:#85E89D;">spec</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  namespaces</span><span style="color:#E1E4E8;">: [</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">  deployments</span><span style="color:#E1E4E8;">: [</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">  services</span><span style="color:#E1E4E8;">: [</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">  configMaps</span><span style="color:#E1E4E8;">: [</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">  ingresses</span><span style="color:#E1E4E8;">: [</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#6A737D;"># Total: 5 resources</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>Impact:</strong></p><ul><li>Fewer resources = Faster reconciliation</li><li>Less API server load</li><li>Lower memory usage</li></ul><h2 id="scaling-considerations" tabindex="-1">Scaling Considerations <a class="header-anchor" href="#scaling-considerations" aria-label="Permalink to &quot;Scaling Considerations&quot;">​</a></h2><h3 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h3><p>Quick reference based on real benchmark data:</p><ul><li>5 nodes: <strong>0 – 5 m</strong> CPU / 10 – 60 MB RAM</li><li><strong>300+ nodes: &lt; 100 m CPU / &lt; 120 MB RAM</strong> — annotation-driven skip path eliminates the per-reconcile API-write cost; the vast majority of reconciles are no-op (hash match ⇒ skip)</li></ul><table tabindex="0"><thead><tr><th>Node count</th><th>CPU request</th><th>CPU limit</th><th>Memory request</th><th>Memory limit</th></tr></thead><tbody><tr><td>&lt; 50</td><td><code>25m</code></td><td><code>100m</code></td><td><code>64Mi</code></td><td><code>128Mi</code></td></tr><tr><td>50–200</td><td><code>50m</code></td><td><code>200m</code></td><td><code>96Mi</code></td><td><code>192Mi</code></td></tr><tr><td>200–500</td><td><code>100m</code></td><td><code>300m</code></td><td><code>128Mi</code></td><td><code>256Mi</code></td></tr><tr><td>500–1000</td><td><code>200m</code></td><td><code>500m</code></td><td><code>256Mi</code></td><td><code>512Mi</code></td></tr><tr><td>1000+</td><td><code>500m</code></td><td><code>1000m</code></td><td><code>512Mi</code></td><td><code>1Gi</code></td></tr></tbody></table><p>CPU is bursty: steady-state is near-idle, with brief spikes during periodic force-reapply (every <code>ForceReapplyInterval</code>, default 10 min) and template-change events. Memory is stable once the controller-runtime informer cache warms up.</p><p>For the explanation of <em>why</em> resources scale this way (cache model, reconciliation burst pattern, concurrency trade-offs), see <a href="./resource-sizing">Resource Sizing</a>.</p><h3 id="database-optimization" tabindex="-1">Database Optimization <a class="header-anchor" href="#database-optimization" aria-label="Permalink to &quot;Database Optimization&quot;">​</a></h3><ol><li><strong>Add indexes</strong> to node table:</li></ol><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">CREATE</span><span style="color:#F97583;"> INDEX</span><span style="color:#B392F0;"> idx_is_active</span><span style="color:#F97583;"> ON</span><span style="color:#E1E4E8;"> node_configs(is_active);</span></span>
<span class="line"><span style="color:#F97583;">CREATE</span><span style="color:#F97583;"> INDEX</span><span style="color:#B392F0;"> idx_node_id</span><span style="color:#F97583;"> ON</span><span style="color:#E1E4E8;"> node_configs(node_id);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="2"><li><p><strong>Use read replicas</strong> for high-frequency syncs</p></li><li><p><strong>Connection pooling</strong>: Operator uses persistent connections</p></li></ol><h2 id="monitoring-performance" tabindex="-1">Monitoring Performance <a class="header-anchor" href="#monitoring-performance" aria-label="Permalink to &quot;Monitoring Performance&quot;">​</a></h2><h3 id="key-metrics-with-thresholds" tabindex="-1">Key Metrics with Thresholds <a class="header-anchor" href="#key-metrics-with-thresholds" aria-label="Permalink to &quot;Key Metrics with Thresholds&quot;">​</a></h3><p>Monitor these Prometheus metrics with specific thresholds:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Target</th><th>Warning</th><th>Critical</th><th>Action</th></tr></thead><tbody><tr><td>Reconciliation P95</td><td>&lt; 5s</td><td>5-15s</td><td>&gt; 15s</td><td>Simplify templates, reduce dependencies</td></tr><tr><td>Reconciliation P99</td><td>&lt; 15s</td><td>15-30s</td><td>&gt; 30s</td><td>Check for blocking resources</td></tr><tr><td>Node Ready Rate</td><td>&gt; 98%</td><td>95-98%</td><td>&lt; 95%</td><td>Check failed nodes, resource issues</td></tr><tr><td>Error Rate</td><td>&lt; 1%</td><td>1-5%</td><td>&gt; 5%</td><td>Investigate operator logs</td></tr><tr><td>Skipped Resources</td><td>0</td><td>1-5</td><td>&gt; 5</td><td>Fix dependency failures</td></tr><tr><td>Conflict Count</td><td>0</td><td>1-3</td><td>&gt; 3</td><td>Review resource ownership</td></tr><tr><td>CPU Usage</td><td>&lt; 50%</td><td>50-80%</td><td>&gt; 80%</td><td>Increase limits or reduce concurrency</td></tr><tr><td>Memory Usage</td><td>&lt; 70%</td><td>70-90%</td><td>&gt; 90%</td><td>Increase limits or restart operator</td></tr><tr><td>Hub Sync Duration</td><td>&lt; 1s</td><td>1-5s</td><td>&gt; 5s</td><td>Optimize DB query, add indexes</td></tr></tbody></table><p><strong>Prometheus Queries:</strong></p><div class="language-promql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span># Reconciliation duration P95 (target: &lt; 5s)</span></span>
<span class="line"><span>histogram_quantile(0.95,</span></span>
<span class="line"><span>  sum(rate(lynqnode_reconcile_duration_seconds_bucket[5m])) by (le)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Reconciliation duration P99 (target: &lt; 15s)</span></span>
<span class="line"><span>histogram_quantile(0.99,</span></span>
<span class="line"><span>  sum(rate(lynqnode_reconcile_duration_seconds_bucket[5m])) by (le)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Node readiness rate (target: &gt; 98%)</span></span>
<span class="line"><span>sum(lynqnode_resources_ready) / sum(lynqnode_resources_desired) * 100</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Error rate (target: &lt; 1%)</span></span>
<span class="line"><span>sum(rate(lynqnode_reconcile_duration_seconds_count{result=&quot;error&quot;}[5m]))</span></span>
<span class="line"><span>/ sum(rate(lynqnode_reconcile_duration_seconds_count[5m])) * 100</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Conflict count by node</span></span>
<span class="line"><span>sum by (lynqnode) (lynqnode_resources_conflicted)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Degraded nodes</span></span>
<span class="line"><span>count(lynqnode_degraded_status == 1)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h3 id="sample-prometheus-alert-rules" tabindex="-1">Sample Prometheus Alert Rules <a class="header-anchor" href="#sample-prometheus-alert-rules" aria-label="Permalink to &quot;Sample Prometheus Alert Rules&quot;">​</a></h3><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># config/prometheus/alerts.yaml</span></span>
<span class="line"><span style="color:#85E89D;">groups</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">lynq-performance</span></span>
<span class="line"><span style="color:#85E89D;">    rules</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">      - </span><span style="color:#85E89D;">alert</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">LynqSlowReconciliation</span></span>
<span class="line"><span style="color:#85E89D;">        expr</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">histogram_quantile(0.95, sum(rate(lynqnode_reconcile_duration_seconds_bucket[5m])) by (le)) &gt; 15</span></span>
<span class="line"><span style="color:#85E89D;">        for</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">5m</span></span>
<span class="line"><span style="color:#85E89D;">        labels</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          severity</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">warning</span></span>
<span class="line"><span style="color:#85E89D;">        annotations</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          summary</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Lynq reconciliation is slow&quot;</span></span>
<span class="line"><span style="color:#85E89D;">          description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;P95 reconciliation time is {{ $value | humanizeDuration }}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">      - </span><span style="color:#85E89D;">alert</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">LynqHighErrorRate</span></span>
<span class="line"><span style="color:#85E89D;">        expr</span><span style="color:#E1E4E8;">: </span><span style="color:#F97583;">|</span></span>
<span class="line"><span style="color:#9ECBFF;">          sum(rate(lynqnode_reconcile_duration_seconds_count{result=&quot;error&quot;}[5m]))</span></span>
<span class="line"><span style="color:#9ECBFF;">          / sum(rate(lynqnode_reconcile_duration_seconds_count[5m])) &gt; 0.05</span></span>
<span class="line"><span style="color:#85E89D;">        for</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">5m</span></span>
<span class="line"><span style="color:#85E89D;">        labels</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          severity</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">critical</span></span>
<span class="line"><span style="color:#85E89D;">        annotations</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          summary</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Lynq error rate above 5%&quot;</span></span>
<span class="line"><span style="color:#85E89D;">          description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Current error rate: {{ $value | humanizePercentage }}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">      - </span><span style="color:#85E89D;">alert</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">LynqLowReadyRate</span></span>
<span class="line"><span style="color:#85E89D;">        expr</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">sum(lynqnode_resources_ready) / sum(lynqnode_resources_desired) &lt; 0.95</span></span>
<span class="line"><span style="color:#85E89D;">        for</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">10m</span></span>
<span class="line"><span style="color:#85E89D;">        labels</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          severity</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">warning</span></span>
<span class="line"><span style="color:#85E89D;">        annotations</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          summary</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Lynq ready rate below 95%&quot;</span></span>
<span class="line"><span style="color:#85E89D;">          description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Only {{ $value | humanizePercentage }} resources are ready&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">      - </span><span style="color:#85E89D;">alert</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">LynqHighMemory</span></span>
<span class="line"><span style="color:#85E89D;">        expr</span><span style="color:#E1E4E8;">: </span><span style="color:#F97583;">|</span></span>
<span class="line"><span style="color:#9ECBFF;">          container_memory_usage_bytes{container=&quot;manager&quot;, namespace=&quot;lynq-system&quot;}</span></span>
<span class="line"><span style="color:#9ECBFF;">          / container_spec_memory_limit_bytes{container=&quot;manager&quot;, namespace=&quot;lynq-system&quot;} &gt; 0.9</span></span>
<span class="line"><span style="color:#85E89D;">        for</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">5m</span></span>
<span class="line"><span style="color:#85E89D;">        labels</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          severity</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">warning</span></span>
<span class="line"><span style="color:#85E89D;">        annotations</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">          summary</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Lynq operator memory above 90%&quot;</span></span>
<span class="line"><span style="color:#85E89D;">          description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Memory usage: {{ $value | humanizePercentage }}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br></div></div><p>See <a href="./monitoring">Monitoring Guide</a> for complete metrics reference.</p><h2 id="bottleneck-identification-priority" tabindex="-1">Bottleneck Identification Priority <a class="header-anchor" href="#bottleneck-identification-priority" aria-label="Permalink to &quot;Bottleneck Identification Priority&quot;">​</a></h2><p>When performance degrades, identify bottlenecks in this order:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span>Performance Issue?</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ Step 1: Check Reconciliation Duration</span></span>
<span class="line"><span>│  $ kubectl logs -n lynq-system deployment/lynq-controller-manager | grep &quot;Reconciliation completed&quot; | tail -20</span></span>
<span class="line"><span>│  │</span></span>
<span class="line"><span>│  ├─ &gt; 15s? → Check dependency depth, waitForReady timeouts</span></span>
<span class="line"><span>│  └─ &lt; 5s? → Continue to Step 2</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ Step 2: Check Hub Sync Duration</span></span>
<span class="line"><span>│  $ kubectl get lynqhub -o jsonpath=&#39;{range .items[*]}{.metadata.name}: {.status.lastSyncDuration}{&quot;\\n&quot;}{end}&#39;</span></span>
<span class="line"><span>│  │</span></span>
<span class="line"><span>│  ├─ &gt; 5s? → Optimize DB query, add indexes</span></span>
<span class="line"><span>│  └─ &lt; 1s? → Continue to Step 3</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ Step 3: Check Resource Usage</span></span>
<span class="line"><span>│  $ kubectl top pods -n lynq-system</span></span>
<span class="line"><span>│  │</span></span>
<span class="line"><span>│  ├─ CPU &gt; 80%? → Increase limits or reduce concurrency</span></span>
<span class="line"><span>│  └─ Memory &gt; 90%? → Increase limits or restart operator</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└─ Step 4: Check Error Rate</span></span>
<span class="line"><span>   $ kubectl logs -n lynq-system deployment/lynq-controller-manager | grep -c ERROR</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ High error count? → Check specific error messages</span></span>
<span class="line"><span>   └─ Low errors? → Performance may be within normal range</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br></div></div><h2 id="troubleshooting-slow-performance" tabindex="-1">Troubleshooting Slow Performance <a class="header-anchor" href="#troubleshooting-slow-performance" aria-label="Permalink to &quot;Troubleshooting Slow Performance&quot;">​</a></h2><h3 id="symptom-slow-node-creation" tabindex="-1">Symptom: Slow Node Creation <a class="header-anchor" href="#symptom-slow-node-creation" aria-label="Permalink to &quot;Symptom: Slow Node Creation&quot;">​</a></h3><p><strong>Check:</strong></p><ol><li>Database query performance</li><li><code>waitForReady</code> timeouts</li><li>Dependency chain depth</li></ol><p><strong>Solution:</strong></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Check reconciliation times</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> logs</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> -l</span><span style="color:#9ECBFF;"> control-plane=controller-manager</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> &quot;Reconciliation completed&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Reduce sync interval if database is slow</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> patch</span><span style="color:#9ECBFF;"> lynqhub</span><span style="color:#9ECBFF;"> my-hub</span><span style="color:#79B8FF;"> --type=merge</span><span style="color:#79B8FF;"> -p</span><span style="color:#9ECBFF;"> &#39;{&quot;spec&quot;:{&quot;source&quot;:{&quot;syncInterval&quot;:&quot;2m&quot;}}}&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="symptom-high-cpu-usage" tabindex="-1">Symptom: High CPU Usage <a class="header-anchor" href="#symptom-high-cpu-usage" aria-label="Permalink to &quot;Symptom: High CPU Usage&quot;">​</a></h3><p><strong>Check:</strong></p><ol><li>Reconciliation frequency</li><li>Template complexity</li><li>Total node count</li></ol><p><strong>Solution:</strong></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Check CPU usage</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> top</span><span style="color:#9ECBFF;"> pods</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Increase resource limits</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> edit</span><span style="color:#9ECBFF;"> deployment</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> lynq-controller-manager</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="symptom-memory-growth" tabindex="-1">Symptom: Memory Growth <a class="header-anchor" href="#symptom-memory-growth" aria-label="Permalink to &quot;Symptom: Memory Growth&quot;">​</a></h3><p><strong>Possible causes:</strong></p><ol><li>Controller-runtime informer caches scale with total watched-resource count (12 native kinds × cluster-wide scope) — proportional to node count and template breadth</li><li>Large rendered template outputs held briefly during reconcile</li><li>Memory leak (file an issue)</li></ol><p>Note: Lynq&#39;s apply path itself holds <strong>no in-memory per-resource cache</strong> — skip decisions read the <code>lynq.sh/applied-hash</code> annotation on each live resource. Restarting the operator does not free any Lynq-specific cache.</p><p><strong>Solution:</strong></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Monitor memory over time</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> top</span><span style="color:#9ECBFF;"> pods</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#79B8FF;"> --watch</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># If growth correlates with node count, tune watch scope or shard concurrency</span></span>
<span class="line"><span style="color:#6A737D;">#   --node-concurrency=N  (lower = lower steady-state memory)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="best-practices-summary" tabindex="-1">Best Practices Summary <a class="header-anchor" href="#best-practices-summary" aria-label="Permalink to &quot;Best Practices Summary&quot;">​</a></h2><ol><li><strong>✅ Start with defaults</strong> - Only optimize if you see issues</li><li><strong>✅ Keep templates simple</strong> - Avoid complex logic and non-deterministic functions</li><li><strong>✅ Use shallow dependency trees</strong> - Enable parallel resource creation</li><li><strong>✅ Set appropriate timeouts</strong> - Balance speed vs reliability</li><li><strong>✅ Monitor key metrics</strong> - Watch reconciliation duration and error rates</li><li><strong>✅ Index your database</strong> - Improve sync query performance</li><li><strong>✅ Use <code>CreationPolicy: Once</code></strong> - For immutable resources</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./monitoring">Monitoring Guide</a> - Complete metrics reference and dashboards</li><li><a href="./prometheus-queries">Prometheus Queries</a> - Ready-to-use queries</li><li><a href="./configuration">Configuration Guide</a> - All operator settings</li><li><a href="./troubleshooting">Troubleshooting Guide</a> - Common issues and solutions</li></ul>`,88)])])}const y=n(o,[["render",p]]);export{m as __pageData,y as default};
